package main.rice.obj;

import java.util.Collection;
import java.util.Iterator;
import java.util.stream.Collectors;

/**
 * Abstract base class for iterable Python objects (list, tuple, set, dict, string).
 *
 * @param <T> the element type stored in this iterable
 */
public abstract class AIterablePyObj<T> extends APyObj<Collection<T>> {

    /**
     * Builds a comma-separated string of elements joined with delimiters.
     */
    protected String buildContents() {
        return value.stream()
            .map(Object::toString)
            .collect(Collectors.joining(", "));
    }
}

package main.rice.obj;

/**
 * Abstract base class for all Python objects.
 *
 * @param <T> the type of the underlying Java value
 */
public abstract class APyObj<T> {

    protected T value;

    /**
     * Returns the underlying Java value.
     */
    public T getValue() {
        return value;
    }

    /**
     * Two APyObj instances are equal if they have the same runtime type AND equal values.
     */
    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null) return false;
        if (this.getClass() != obj.getClass()) return false;
        APyObj<?> other = (APyObj<?>) obj;
        return this.value.equals(other.value);
    }

    @Override
    public int hashCode() {
        return value.hashCode();
    }

    @Override
    public abstract String toString();
}

package main.rice.obj;

/**
 * Represents a Python boolean object (True or False).
 */
public class PyBoolObj extends APyObj<Boolean> {

    public PyBoolObj(Boolean value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return value ? "True" : "False";
    }
}

package main.rice.obj;

/**
 * Represents a Python character (single-character string).
 */
public class PyCharObj extends APyObj<Character> {

    public PyCharObj(Character value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return "'" + value + "'";
    }
}

package main.rice.obj;

import java.util.Map;
import java.util.stream.Collectors;

/**
 * Represents a Python dictionary object.
 *
 * @param <K> the key type
 * @param <V> the value type
 */
public class PyDictObj<K extends APyObj<?>, V extends APyObj<?>> extends APyObj<Map<K, V>> {

    public PyDictObj(Map<K, V> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        String contents = value.entrySet().stream()
            .map(e -> e.getKey().toString() + ": " + e.getValue().toString())
            .collect(Collectors.joining(", "));
        return "{" + contents + "}";
    }
}

package main.rice.obj;

/**
 * Represents a Python float object.
 */
public class PyFloatObj extends APyObj<Double> {

    public PyFloatObj(Double value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return value.toString();
    }
}

package main.rice.obj;

/**
 * Represents a Python integer object.
 */
public class PyIntObj extends APyObj<Integer> {

    public PyIntObj(Integer value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return value.toString();
    }
}

package main.rice.obj;

import java.util.List;
import java.util.stream.Collectors;

/**
 * Represents a Python list object.
 *
 * @param <T> the element type
 */
public class PyListObj<T extends APyObj<?>> extends APyObj<List<T>> {

    public PyListObj(List<T> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        String contents = value.stream()
            .map(Object::toString)
            .collect(Collectors.joining(", "));
        return "[" + contents + "]";
    }
}

package main.rice.obj;

import java.util.Set;
import java.util.stream.Collectors;

/**
 * Represents a Python set object.
 *
 * @param <T> the element type
 */
public class PySetObj<T extends APyObj<?>> extends APyObj<Set<T>> {

    public PySetObj(Set<T> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "set()";
        }
        String contents = value.stream()
            .map(Object::toString)
            .collect(Collectors.joining(", "));
        return "{" + contents + "}";
    }
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.List;

/**
 * Represents a Python string object (stored as a list of PyCharObj).
 */
public class PyStringObj extends APyObj<List<PyCharObj>> {

    private final String rawString;

    public PyStringObj(String str) {
        this.rawString = str;
        List<PyCharObj> chars = new ArrayList<>();
        for (char c : str.toCharArray()) {
            chars.add(new PyCharObj(c));
        }
        this.value = chars;
    }

    @Override
    public String toString() {
        return "'" + rawString + "'";
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || this.getClass() != obj.getClass()) return false;
        PyStringObj other = (PyStringObj) obj;
        return this.rawString.equals(other.rawString);
    }

    @Override
    public int hashCode() {
        return rawString.hashCode();
    }
}

package main.rice.obj;

import java.util.List;
import java.util.stream.Collectors;

/**
 * Represents a Python tuple object.
 *
 * @param <T> the element type
 */
public class PyTupleObj<T extends APyObj<?>> extends APyObj<List<T>> {

    public PyTupleObj(List<T> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        if (value.size() == 1) {
            return "(" + value.get(0).toString() + ",)";
        }
        String contents = value.stream()
            .map(Object::toString)
            .collect(Collectors.joining(", "));
        return "(" + contents + ")";
    }
}

